export default class Support{constructor(e){this.app=e}init(){const e=this;barba.init({debug:!0,transitions:[{name:"lifecycle-transition",async leave(a){console.log("Lifecycle: 1. Leaving current page..."),await e.app.transition.out()},async enter(a){await e.app.route.router.resolve(a.next.namespace),e.app.cursor.refresh(),await e.app.transition.in(),console.log("Lifecycle: 2. New container arrived.");const t=a.next.namespace;await e.app.route.router.resolve(t),e.app.cursor.refresh(),console.log(`Lifecycle: 3. Controller [${t}] mounted.`),await e.app.transition.in()}}]})}}